 1→<?php
 2→
 3→namespace App\Workflows\Common;
 4→
 5→use App\Contracts\Lock\Repository;
 6→use App\Models\WorkflowVersion;
 7→
 8→/**
 9→ * 缓存所有审批流程的最新版本号.
10→ */
11→class WorkflowVersionData
12→{
13→    public const RK_DATA = __CLASS__.'__PROCESSKEY__';
14→
15→    public const RK_CLEAR_IN_PROGRESS = __CLASS__.'__CREATE_IN_PROGRESS__';
16→
17→    public const TTL = 30 * 24 * 3600;
18→
19→    public static function getData(string $processKey): int
20→    {
21→        $exists = redis()->exists(self::RK_DATA);
22→        $data = redis()->hGet(self::RK_DATA, $processKey);
23→        if (!$data) {
24→            // 如果 redis 中不存在数据，首先从 DB 中 fetch
25→            /** @var WorkflowVersion $wid */
26→            $wid = WorkflowVersion::where('process_key', $processKey)->first();
27→            if (!$wid) {
28→                return -1;
29→            }
30→            $data = $wid->version;
31→            redis()->hSet(self::RK_DATA, $processKey, $data);
32→        }
33→
34→        $exists || redis()->expire(self::RK_DATA, static::TTL); // 第一次初始化则设置为 30天 过期
35→        return (int)$data;
36→    }
37→
38→    public static function clearData($repository = null)
39→    {
40→        if (!$repository) {
41→            $repository = app(Repository::class);
42→        }
43→        if ($repository->create(self::RK_CLEAR_IN_PROGRESS, 10)) {
44→            $hashKeys = redis()->hKeys(self::RK_DATA);
45→            // 以 100 为分块
46→            collect($hashKeys)->chunk(100)->each(function ($keys) {
47→                // https://redis.io/commands/hdel
48→                // 2.4 支持删除多个 key
49→                redis()->hDel(self::RK_DATA, ...$keys->toArray());
50→            });
51→            // 删除多个 key 之后，外部的 key 也会被删除，这里为了保证一致性，再对外面的 key 删除一次
52→            redis()->del(self::RK_DATA);
53→            $repository->forget(self::RK_CLEAR_IN_PROGRESS);
54→        }
55→    }
56→}
