23→     * @var string
24→     */
25→    protected $description = 'initialize process version';
26→
27→    /**
28→     * Create a new command instance.
29→     *
30→     * @return void
31→     */
32→    public function __construct()
33→    {
34→        parent::__construct();
35→    }
36→
37→    /**
38→     * Execute the console command.
39→     *
40→     * @return int
41→     */
42→    public function handle(): int
43→    {
44→        $oldProcesses = WorkflowVersion::pluck('process_key')->toArray();
45→        $newProcesses = array_keys(Registry::PROCESS_MAPS);
46→
47→        $data = [];
48→        foreach (array_diff($newProcesses, $oldProcesses) as $processKey) {
49→            $data[] = [
50→                'process_key' => $processKey,
51→                'version' => 1,
52→                'created_at' => Carbon::now(),
53→                'updated_at' => Carbon::now(),
54→            ];
55→        }
56→        WorkflowVersion::insertOrIgnore($data);
57→
58→        WorkflowVersionData::clearData();
59→
60→        return 0;
61→    }
