 3→namespace App\Console\Commands;
 4→
 5→use App\Models\WorkflowVersion;
 6→use App\Workflows\Common\Registry;
 7→use App\Workflows\Common\WorkflowVersionData;
 8→use Illuminate\Console\Command;
 9→
10→class updateWorkflowVersion extends Command
11→{
12→    /**
13→     * The name and signature of the console command.
14→     *
15→     * @var string
16→     */
17→    protected $signature = 'workflow-version:update {process_key}';
18→
19→    /**
20→     * The console command description.
21→     *
22→     * @var string
23→     */
24→    protected $description = 'update process version';
25→
26→    /**
27→     * Create a new command instance.
28→     *
29→     * @return void
30→     */
31→    public function __construct()
32→    {
33→        parent::__construct();
34→    }
35→
36→    /**
37→     * Execute the console command.
38→     *
39→     * @return int
40→     */
41→    public function handle(): int
42→    {
43→        $processKey = (string)$this->argument('process_key');
44→
45→        $query = WorkflowVersion::where('process_key', $processKey)->first();
46→        if ($query == null) {
47→            $this->info("Process Key {$processKey} does not exist.\n");
48→            return 0;
49→        }
50→
51→        $stateClassName = Registry::STATE_MAPS[$processKey]['class'];
52→        $newVersion = $query->version + 1;
53→        if (!in_array($newVersion, $stateClassName::get_all_versions())) {
54→            $this->info("Invalid Version {$newVersion}\n");
55→            return 0;
56→        }
57→
58→        WorkflowVersion::where('process_key', $processKey)->increment('version', 1);
59→        WorkflowVersionData::clearData();
60→
61→        return 0;
62→    }
63→}
